async () => {
  const press = (key) => window.dispatchEvent(new KeyboardEvent('keydown', { key, bubbles: true }));
  const release = (key) => window.dispatchEvent(new KeyboardEvent('keyup', { key, bubbles: true }));
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const normalize = (angle) => Math.atan2(Math.sin(angle), Math.cos(angle));
  const checkpointsReached = [];

  for (let i = 0; i < 480; i += 1) {
    const s = window.__checkpointSprint.getState();
    checkpointsReached.push(s.checkpointIndex);
    if (s.mode !== 'racing') break;
    const target = s.nextCheckpoint;
    const desired = Math.atan2(target.y - s.y, target.x - s.x);
    const diff = normalize(desired - s.angle);
    press('w');
    if (diff < -0.08) {
      press('a');
      release('d');
    } else if (diff > 0.08) {
      press('d');
      release('a');
    } else {
      release('a');
      release('d');
    }
    await sleep(33);
  }
  release('w');
  release('a');
  release('d');
  await sleep(100);
  const finalState = window.__checkpointSprint.getState();
  return {
    finalState,
    maxCheckpointIndex: Math.max(...checkpointsReached),
    progressText: document.querySelector('#progress').textContent,
    timerText: document.querySelector('#timer').textContent,
    overlayHidden: document.querySelector('#message').classList.contains('hidden'),
    overlayTitle: document.querySelector('#message h1').textContent,
    overlayText: document.querySelector('#message p').textContent,
  };
}

